class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def getNthFromEnd(head: ListNode, n: int) -> ListNode:
    if not head:
        return None

    slow = head
    fast = head

    # Move fast pointer n steps ahead
    for _ in range(n):
        if not fast:
            # If fast becomes None, n is greater than the list length
            return None
        fast = fast.next

    # If fast is None at this point, it means n was exactly the length of the list.
    # In this case, the head is the Nth node from the end.
    if not fast:
        return head

    # Move both pointers until fast reaches the end (fast.next is None)
    while fast.next:
        slow = slow.next
        fast = fast.next

    # At this point, fast is the last node. slow.next is the Nth node from the end.
    return slow.next
